92	  const branchByName = useMemo(
93	    () => new Map(branches.map((branch) => [branch.name, branch] as const)),
94	    [branches],
95	  );
96	  const trimmedBranchQuery = branchQuery.trim();
97	  const normalizedBranchQuery = trimmedBranchQuery.toLowerCase();
98	  const canCreateBranch = effectiveEnvMode === "local" && trimmedBranchQuery.length > 0;
99	  const hasExactBranchMatch = branchByName.has(trimmedBranchQuery);
100	  const createBranchItemValue = canCreateBranch
101	    ? `__create_new_branch__:${trimmedBranchQuery}`
102	    : null;
103	  const branchPickerItems = useMemo(
104	    () =>
105	      createBranchItemValue && !hasExactBranchMatch
106	        ? [...branchNames, createBranchItemValue]
