115	            if (createBranchItemValue && itemValue === createBranchItemValue) return true;
116	            return itemValue.toLowerCase().includes(normalizedBranchQuery);
117	          }),
118	    [branchPickerItems, createBranchItemValue, normalizedBranchQuery],
119	  );
