121	    canonicalActiveBranch,
122	    (_currentBranch: string | null, optimisticBranch: string | null) => optimisticBranch,
123	  );
124	  const [isBranchActionPending, startBranchActionTransition] = useTransition();
125	
126	  const runBranchAction = (action: () => Promise<void>) => {
127	    startBranchActionTransition(async () => {
128	      await action().catch(() => undefined);
