136	
137	    // In new-worktree mode, selecting a branch sets the base branch.
138	    if (effectiveEnvMode === "worktree" && !envLocked && !activeWorktreePath) {
139	      onSetThreadBranch(branch.name, null);
140	      setIsBranchMenuOpen(false);
141	      onComposerFocusRequest?.();
