259	function resolveWsRpc(tag: string): unknown {
260	  if (tag === ORCHESTRATION_WS_METHODS.getSnapshot) {
261	    return fixture.snapshot;
262	  }
263	  if (tag === WS_METHODS.serverGetConfig) {
264	    return fixture.serverConfig;
265	  }
266	  if (tag === WS_METHODS.gitListBranches) {
267	    return {
268	      isRepo: true,
269	      branches: [
270	        {
271	          name: "main",
272	          current: true,
273	          isDefault: true,
274	          worktreePath: null,
275	        },
276	      ],
277	    };
278	  }
279	  if (tag === WS_METHODS.gitStatus) {
280	    return {
281	      branch: "main",
282	      hasWorkingTreeChanges: false,
283	      workingTree: {
284	        files: [],
285	        insertions: 0,
286	        deletions: 0,
287	      },
288	      hasUpstream: true,
289	      aheadCount: 0,
290	      behindCount: 0,
291	      pr: null,
292	    };
293	  }
294	  if (tag === WS_METHODS.projectsSearchEntries) {
295	    return {
296	      entries: [],
297	      truncated: false,
298	    };
299	  }
300	  return {};
301	}
