312	    client.addEventListener("message", (event) => {
313	      const rawData = event.data;
314	      if (typeof rawData !== "string") return;
315	      let request: WsRequestEnvelope;
316	      try {
317	        request = JSON.parse(rawData) as WsRequestEnvelope;
318	      } catch {
319	        return;
320	      }
321	      const method = request.body?._tag;
322	      if (typeof method !== "string") return;
323	      wsRequests.push(request.body);
324	      client.send(
325	        JSON.stringify({
326	          id: request.id,
327	          result: resolveWsRpc(method),
328	        }),
329	      );
330	    });
331	  }),
