412	async function waitForImagesToLoad(scope: ParentNode): Promise<void> {
413	  const images = Array.from(scope.querySelectorAll("img"));
414	  if (images.length === 0) {
415	    return;
416	  }
417	  await Promise.all(
418	    images.map(
419	      (image) =>
420	        new Promise<void>((resolve) => {
421	          if (image.complete) {
422	            resolve();
423	            return;
424	          }
425	          image.addEventListener("load", () => resolve(), { once: true });
426	          image.addEventListener("error", () => resolve(), { once: true });
427	        }),
428	    ),
429	  );
430	  await waitForLayout();
