433	async function measureUserRow(options: {
434	  host: HTMLElement;
435	  targetMessageId: MessageId;
436	}): Promise<UserRowMeasurement> {
437	  const { host, targetMessageId } = options;
438	  const rowSelector = `[data-message-id="${targetMessageId}"][data-message-role="user"]`;
439	
440	  const scrollContainer = await waitForElement(
441	    () => host.querySelector<HTMLDivElement>("div.overflow-y-auto.overscroll-y-contain"),
442	    "Unable to find ChatView message scroll container.",
443	  );
444	
445	  let row: HTMLElement | null = null;
446	  await vi.waitFor(
447	    async () => {
448	      scrollContainer.scrollTop = 0;
449	      scrollContainer.dispatchEvent(new Event("scroll"));
450	      await waitForLayout();
451	      row = host.querySelector<HTMLElement>(rowSelector);
452	      expect(row, "Unable to locate targeted user message row.").toBeTruthy();
453	    },
454	    {
455	      timeout: 8_000,
456	      interval: 16,
457	    },
458	  );
459	
460	  await waitForImagesToLoad(row!);
461	  scrollContainer.scrollTop = 0;
462	  scrollContainer.dispatchEvent(new Event("scroll"));
463	  await nextFrame();
464	
465	  const timelineRoot =
466	    row!.closest<HTMLElement>('[data-timeline-root="true"]') ??
467	    host.querySelector<HTMLElement>('[data-timeline-root="true"]');
468	  if (!(timelineRoot instanceof HTMLElement)) {
469	    throw new Error("Unable to locate timeline root container.");
470	  }
471	
472	  let timelineWidthMeasuredPx = 0;
473	  let measuredRowHeightPx = 0;
474	  let renderedInVirtualizedRegion = false;
475	  await vi.waitFor(
476	    async () => {
477	      scrollContainer.scrollTop = 0;
478	      scrollContainer.dispatchEvent(new Event("scroll"));
479	      await nextFrame();
480	      const measuredRow = host.querySelector<HTMLElement>(rowSelector);
481	      expect(measuredRow, "Unable to measure targeted user row height.").toBeTruthy();
482	      timelineWidthMeasuredPx = timelineRoot.getBoundingClientRect().width;
483	      measuredRowHeightPx = measuredRow!.getBoundingClientRect().height;
484	      renderedInVirtualizedRegion = measuredRow!.closest("[data-index]") instanceof HTMLElement;
485	      expect(timelineWidthMeasuredPx, "Unable to measure timeline width.").toBeGreaterThan(0);
486	      expect(measuredRowHeightPx, "Unable to measure targeted user row height.").toBeGreaterThan(0);
487	    },
488	    {
489	      timeout: 4_000,
490	      interval: 16,
491	    },
492	  );
493	
494	  return { measuredRowHeightPx, timelineWidthMeasuredPx, renderedInVirtualizedRegion };
495	}
