10	import { createJSONStorage, persist } from "zustand/middleware";
11	import {
12	  DEFAULT_THREAD_TERMINAL_HEIGHT,
13	  DEFAULT_THREAD_TERMINAL_ID,
14	  MAX_THREAD_TERMINAL_COUNT,
15	  type ThreadTerminalGroup,
16	} from "./types";
