  }

  const { tokens } = themeOption;
  return (
    <div
      className="size-8 shrink-0 overflow-hidden rounded-md border border-border"
      aria-hidden="true"
      style={{ background: tokens.background }}
    >
      <div className="flex h-full">
        <div className="h-full w-2.5" style={{ background: tokens.sidebar }} />
        <div className="flex flex-1 flex-col justify-end">
          <div className="h-1" style={{ background: tokens.primary }} />
        </div>
      </div>
    </div>
  );
}

type SelectorEntry =
  | { kind: "system"; value: "system"; label: string; description: string }
  | { kind: "theme"; themeOption: ThemeDefinition };

const SELECTOR_ENTRIES: SelectorEntry[] = [
  { kind: "system", value: "system", label: "System", description: "Match your OS appearance setting." },
  ...THEME_LIST.map((t): SelectorEntry => ({ kind: "theme", themeOption: t })),
];

export function ThemeSelector() {
  const { theme, setTheme, resolvedThemeId } = useTheme();

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
        {SELECTOR_ENTRIES.map((entry) => {
          const value: ColorThemeSelection = entry.kind === "system" ? "system" : entry.themeOption.id;
          const label = entry.kind === "system" ? entry.label : entry.themeOption.label;
          const description =
            entry.kind === "system"
              ? entry.description
              : entry.themeOption.isDark
                ? "Dark theme."
                : "Light theme.";
          const selected = theme === value;

          return (
            <button
              key={value}
              type="button"
              role="radio"
              aria-checked={selected}
              className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent"
              }`}
              onClick={() => setTheme(value)}
            >
              <ThemeSwatch themeOption={entry.kind === "system" ? "system" : entry.themeOption} />
              <span className="flex flex-1 flex-col">
                <span className="text-sm font-medium">{label}</span>
                <span className="text-xs">{description}</span>
              </span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Selected
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
