### 6. MODIFY: `apps/web/src/hooks/useTheme.ts` (full rewrite)

Preserves the `useSyncExternalStore` + module-level state pattern exactly. Key changes:

- New storage key: `"t3code:color-theme"` (old key: `"t3code:theme"`)
- One-time migration: on first load, read old key, map `"light"→"t3-light"`, `"dark"→"t3-dark"`, `"system"→"system"`, write to new key, delete old key
- `applyTheme()` iterates `Object.entries(theme.tokens)` and calls `style.setProperty("--" + key.replace(/([A-Z])/g, "-$1").toLowerCase(), value)` for each token, plus sets `color-scheme` and toggles `.dark` class
- Return type now includes `resolvedThemeId: ThemeId` and `resolvedTheme: ThemeDefinition`

```typescript
import { useCallback, useEffect, useSyncExternalStore } from "react";
import type { ColorThemeSelection, ThemeDefinition, ThemeId } from "@t3tools/contracts";
import { getTheme, resolveThemeId, THEME_IDS } from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:color-theme";
const LEGACY_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
type ThemeSnapshot = { selection: ColorThemeSelection; systemDark: boolean };
let lastSnapshot: ThemeSnapshot | null = null;
let migrationDone = false;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function migrateFromLegacy(): void {
  if (migrationDone) return;
  migrationDone = true;
  if (localStorage.getItem(STORAGE_KEY) !== null) return;
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy === null) return;
  let migrated: ColorThemeSelection = "system";
  if (legacy === "light") migrated = "t3-light";
  else if (legacy === "dark") migrated = "t3-dark";
  localStorage.setItem(STORAGE_KEY, migrated);
  localStorage.removeItem(LEGACY_STORAGE_KEY);
}

function getStored(): ColorThemeSelection {
  migrateFromLegacy();
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "system") return "system";
  if ((THEME_IDS as readonly string[]).includes(raw ?? "")) return raw as ThemeId;
  return "system";
}

function applyTheme(selection: ColorThemeSelection, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const themeId = resolveThemeId(selection, getSystemDark());
  const theme = getTheme(themeId);
  const style = document.documentElement.style;

  for (const [key, value] of Object.entries(theme.tokens)) {
    style.setProperty("--" + key.replace(/([A-Z])/g, "-$1").toLowerCase(), value);
  }
  document.documentElement.classList.toggle("dark", theme.isDark);
  style.setProperty("color-scheme", theme.isDark ? "dark" : "light");

  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): ThemeSnapshot {
  const selection = getStored();
  const systemDark = selection === "system" ? getSystemDark() : false;
  if (lastSnapshot?.selection === selection && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }
  lastSnapshot = { selection, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedThemeId: ThemeId = resolveThemeId(snapshot.selection, getSystemDark());
  const resolvedTheme: ThemeDefinition = getTheme(resolvedThemeId);

  const setTheme = useCallback((next: ColorThemeSelection) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  useEffect(() => {
    applyTheme(snapshot.selection);
  }, [snapshot.selection]);

  return { theme: snapshot.selection, setTheme, resolvedTheme, resolvedThemeId } as const;
}
```

**FOUC prevention note:** The module-level `applyTheme(getStored())` runs when `useTheme.ts` is first imported. Currently `useTheme` is only imported by the settings route, which is code-split. To guarantee the theme applies before any content paints, add a `useTheme()` call (or a bare import) to `apps/web/src/routes/__root.tsx` so the module loads at app startup. The simplest approach: call `useTheme()` inside `RootRouteView` (or `EventRouter`). If `ChatMarkdown.tsx` already imports `useTheme` (it uses `resolvedTheme` for Shiki), it may already be bundled early — verify this.

