import type { ColorThemeSelection, ThemeDefinition, ThemeId } from "@t3tools/contracts";

const T3_LIGHT: ThemeDefinition = {
  id: "t3-light",
  label: "T3 Light",
  isDark: false,
  tokens: {
    // Matches existing :root light-mode CSS defaults exactly
    background: "#ffffff",
    foreground: "#262626",
    card: "#ffffff",
    cardForeground: "#262626",
    popover: "#ffffff",
    popoverForeground: "#262626",
