    terminalForeground: "#f5f5f5",
    statusBar: "#111111",
    statusBarForeground: "#a3a3a3",
  },
};

const T3_MIDNIGHT: ThemeDefinition = {
  id: "t3-midnight",
  label: "Midnight",
  isDark: true,
  tokens: {
    // Deep navy/blue palette — distinctive from T3 Dark
    background: "#080c14",
    foreground: "#e2e8f0",
    card: "#0b1018",
    cardForeground: "#e2e8f0",
    popover: "#0b1018",
    popoverForeground: "#e2e8f0",
    primary: "oklch(0.65 0.22 240)",
    primaryForeground: "#ffffff",
    secondary: "rgba(255,255,255,0.05)",
    secondaryForeground: "#e2e8f0",
    muted: "rgba(255,255,255,0.05)",
    mutedForeground: "#94a3b8",
    accent: "rgba(255,255,255,0.05)",
    accentForeground: "#e2e8f0",
    destructive: "#f16060",
    destructiveForeground: "#f87171",
    border: "rgba(148,163,184,0.12)",
    input: "rgba(148,163,184,0.15)",
    ring: "oklch(0.65 0.22 240)",
    sidebar: "#060a11",
    sidebarForeground: "#e2e8f0",
    editor: "#0b1018",
    editorForeground: "#e2e8f0",
    terminal: "#040608",
    terminalForeground: "#e2e8f0",
    statusBar: "#060a11",
    statusBarForeground: "#94a3b8",
  },
};

/** All built-in theme IDs in display order. */
export const THEME_IDS: readonly ThemeId[] = ["t3-light", "t3-dark", "t3-midnight"];

/** All built-in themes indexed by ID for O(1) lookup. */
export const THEMES: Record<ThemeId, ThemeDefinition> = {
  "t3-light": T3_LIGHT,
  "t3-dark": T3_DARK,
  "t3-midnight": T3_MIDNIGHT,
};

/** All built-in themes as an ordered array for iteration/display. */
export const THEME_LIST: readonly ThemeDefinition[] = THEME_IDS.map((id) => THEMES[id]);

/** Returns the theme definition for a given ID. */
export function getTheme(id: ThemeId): ThemeDefinition {
  return THEMES[id];
}

/**
 * Resolves a user selection (including "system") to a concrete ThemeId.
 * Pure function — no browser APIs, safe to call anywhere including tests.
 */
export function resolveThemeId(
  selection: ColorThemeSelection,
  systemIsDark: boolean,
): ThemeId {
  if (selection === "system") {
    return systemIsDark ? "t3-dark" : "t3-light";
  }
  return selection;
}

